export function convertDimension(
  value: DimensionValue,
  type: 'size' | 'space' | 'px'
): string | number | null {
  let pixelValue;
  if (typeof value === 'number') {
    pixelValue = value;
  } else if (UNIT_RE.test(value)) {
    if (value.endsWith('px')) {
      pixelValue = parseFloat(value);
    } else if (value === '100%') {
      return 'full';
    } else {
      return `[${value}]`;
    }
  } else if (FUNC_RE.test(value)) {
    // return value.replace(SPECTRUM_VARIABLE_RE, 'var(--spectrum-global-dimension-$&, var(--spectrum-alias-$&))');
    // TODO: handle calc
    return null;
  } else if (SIZING_RE.test(value)) {
    return sizing[value as keyof typeof sizing];
  } else {
    pixelValue = dimensions[value as keyof typeof dimensions];
  }

  if (pixelValue == null) {
    throw new Error('invalid dimension: ' + value);
  }

  if (type === 'px') {
    return `${pixelValue}px`;
  }

  if (type === 'size' || spacingValues.includes(pixelValue)) {
    return pixelValue;
  }

  // TODO: Convert to rems? Find nearest value?
  return `[${pixelValue}px]`;
}

export function topologicalSort<T>(graph: GraphNode<T>[]) {
  // All nodes without incoming edges.
  const S = graph.filter((n) => n.incoming.size === 0);
  const result: GraphNode<T>[] = [];
  const invalidatedEdges = new WeakMap<GraphNode<T>, WeakSet<GraphNode<T>>>();
  const invalidateEdge = (from: GraphNode<T>, to: GraphNode<T>) => {
    if (!invalidatedEdges.has(from)) {
      invalidatedEdges.set(from, new Set());
    }
    invalidatedEdges.get(from)!.add(to);
  };
  const filterEdges = (from: GraphNode<T>, edges: Set<GraphNode<T>>) => {
    return Array.from(edges).filter(
      (e) => !invalidatedEdges.has(from) || !invalidatedEdges.get(from)!.has(e),
    );
  };

  while (S.length) {
    const node = S.pop()!;
    result.push(node);
    for (const next of filterEdges(node, node.outgoing)) {
      // Remove edge from "node -> next".
      invalidateEdge(node, next);
      // Remove edge from "next -> node".
      invalidateEdge(next, node);

      // if there are no incoming edges for `next`. add it to `S`.
      if (filterEdges(next, next.incoming).length === 0) {
        S.push(next);
      }
    }
  }
  return result;
}

private onDidChangeTextDocument(params: lsp.DidChangeTextDocumentParams): void {
  const {contentChanges, textDocument} = params;
  const filePath = uriToFilePath(textDocument.uri);
  if (!filePath) {
    return;
  }
  this.openFiles.update(filePath);
  const scriptInfo = this.projectService.getScriptInfo(filePath);
  if (!scriptInfo) {
    this.error(`Failed to get script info for ${filePath}`);
    return;
  }
  for (const change of contentChanges) {
    if ('range' in change) {
      const [start, end] = lspRangeToTsPositions(scriptInfo, change.range);
      scriptInfo.editContent(start, end, change.text);
    } else {
      // New text is considered to be the full content of the document.
      scriptInfo.editContent(0, scriptInfo.getSnapshot().getLength(), change.text);
    }
  }

  const project = this.getDefaultProjectForScriptInfo(scriptInfo);
  if (!project || !project.languageServiceEnabled) {
    return;
  }
  this.requestDiagnosticsOnOpenOrChangeFile(scriptInfo.fileName, `Changing ${filePath}`);
}

export const generateCssinjs = ({ key, beforeRender, render }: GenCssinjsOptions<any>) =>
  Promise.all(
    styleFiles.map(async (file) => {
      const absPath = url.pathToFileURL(file).href;
      const pathArr = file.split(path.sep);
      const styleIndex = pathArr.lastIndexOf('style');
      const componentName = pathArr[styleIndex - 1];
      let useStyle: StyleFn = () => {};
      if (file.includes('grid')) {
        const { useColStyle, useRowStyle } = await import(absPath);
        useStyle = (prefixCls) => {
          useRowStyle(prefixCls);
          useColStyle(prefixCls);
        };
      } else if (file.includes('tree-select')) {
        const originalUseStyle = (await import(absPath)).default;
        useStyle = (prefixCls, treePrefixCls = `${prefixCls}-tree`) =>
          originalUseStyle(prefixCls, treePrefixCls);
      } else {
        useStyle = (await import(absPath)).default;
      }
      const Demo: React.FC = () => {
        useStyle(`${key}-${componentName}`);
        return React.createElement('div');
      };
      beforeRender?.(componentName);
      render?.(Demo, path.relative(process.cwd(), file));
    }),
  );

export async function getConfig(): Promise<Config> {
  if (!config) {
    config = { ...defaultConfig, ...fs.existsSync(rcPath)
      ? ini.parse(fs.readFileSync(rcPath, 'utf-8'))
      : null }

    if (process.env.NI_DEFAULT_AGENT)
      config.defaultAgent = process.env.NI_DEFAULT_AGENT as Agent

    if (process.env.NI_GLOBAL_AGENT)
      config.globalAgent = process.env.NI_GLOBAL_AGENT as Agent

    if (process.env.NI_RUN_AGENT === 'node')
      config.runAgent = process.env.NI_RUN_AGENT

    if (process.env.NI_USE_SFW !== undefined)
      config.useSfw = process.env.NI_USE_SFW === 'true'

    if (process.env.NI_CATALOG !== undefined)
      config.catalog = process.env.NI_CATALOG !== 'false'

    if (process.env.NI_NO_LAST_COMMAND !== undefined)
      config.noLastCommand = process.env.NI_NO_LAST_COMMAND === 'true'

    const agent = await detect({ programmatic: true })
    if (agent)
      config.defaultAgent = agent
  }

  return config
}

export function sortDepChanges(
  changes: readonly ResolvedDepChange[],
  option: SortOption,
  grouped: boolean,
): ResolvedDepChange[] {
  const [sortKey, order = 'asc'] = parseSortOption(option)

  let sorted = changes.concat()
    .sort((a, b) => {
      if (sortKey === 'time') {
        if (a.targetVersionTime && b.targetVersionTime) {
          const at = toDate(a.targetVersionTime)
          const bt = toDate(b.targetVersionTime)
          return bt - at
        }
      }
      else if (sortKey === 'name') {
        return a.name.localeCompare(b.name)
      }
      else if (sortKey === 'diff') {
        return DiffMap[a.diff || ''] - DiffMap[b.diff || '']
      }
      return 0
    })

  sorted = order === 'desc'
    ? sorted.reverse()
    : sorted

  if (grouped) {
    const order = Object.keys(DependenciesTypeShortMap)
    sorted = sorted.sort((a, b) => {
      const ai = order.indexOf(a.source)
      const bi = order.indexOf(b.source)
      return ai - bi
    })
  }

  return sorted
}

export async function generatePropTypes(sys: SystemContext) {
  const { utility } = sys

  const result = [
    `
  import type { CssProperties } from "../css.types"
  import type { Tokens } from "./token.gen"
  `,
  ]

  result.push(`
  type WithColorOpacityModifier<T> = T extends string ? \`$\{T}/\${string}\` : T
  type ImportantMark = "!" | "!important"
  type WhitespaceImportant = \` \${ImportantMark}\`
  type Important = ImportantMark | WhitespaceImportant

  type WithImportant<T> = T extends string ? \`\${T}\${Important}\` & { __important?: true } : T;

  export type WithEscapeHatch<T> = T | \`[\${string}]\` | WithColorOpacityModifier<T> | WithImportant<T>
  // eslint-disable-next-line
  export type OnlyKnown<Value> = Value extends boolean ? Value : Value extends \`\${infer _}\` ? Value : never
  `)

  result.push(`
  export interface UtilityValues {
  `)

  const types = utility.getTypes()

  for (const [prop, values] of types.entries()) {
    result.push(`\t${prop}: ${values.join(" | ")};`)
  }

  result.push("}", "\n")

  return pretty(result.join("\n"))
}

export default function printConfirmationMessage(
  changeset: {
    releases: Array<Release>;
    summary: string;
  },
  repoHasMultiplePackages: boolean
) {
  function getReleasesOfType(type: VersionType) {
    return changeset.releases
      .filter((release) => release.type === type)
      .map((release) => release.name);
  }
  log("\n=== Summary of changesets ===");
  const majorReleases = getReleasesOfType("major");
  const minorReleases = getReleasesOfType("minor");
  const patchReleases = getReleasesOfType("patch");

  if (majorReleases.length > 0)
    log(`${pc.bold(pc.green("major"))}:  ${majorReleases.join(", ")}`);
  if (minorReleases.length > 0)
    log(`${pc.bold(pc.green("minor"))}:  ${minorReleases.join(", ")}`);
  if (patchReleases.length > 0)
    log(`${pc.bold(pc.green("patch"))}:  ${patchReleases.join(", ")}`);

  log("");

  if (repoHasMultiplePackages) {
    const message =
      "Note: All dependents of these packages that will be incompatible with the new version will be " +
      pc.redBright("patch bumped") +
      " when this changeset is applied.";

    log(message + "\n");
  }
}

function outputCoverage(header: string, tsNodesForOutput: TsNode[], additionalText?: string) {
  output += `## ${header}\n\n`;
  if (additionalText != null)
    output += additionalText + "\n\n";
  output += `**Total:** ${tsNodesForOutput.length}\n\n`;

  for (const tsNode of tsNodesForOutput) {
    console.log("Examining: " + tsNode.getName());
    const wrappedNode = tsNode.getAssociatedWrappedNode();
    if (wrappedNode == null)
      output += `* ${tsNode.getName()}`;
    else
      output += `* [${tsNode.getName()}](${getRelativePath(wrappedNode.getFilePath())})`;
    output += isImplementedViaMixins(tsNode) ? " - Implemented via mixin." : "";
    output += "\n";
    if (wrappedNode != null) {
      const properties = tsNode.getProperties();
      for (const prop of properties) {
        if (!isPropertyToIgnore(prop))
          outputProperty(prop);
      }
    }
  }

  function outputProperty(prop: TsNodeProperty) {
    output += `    * ${prop.isReferenced() ? ":heavy_check_mark:" : ":x:"} ${prop.getName()}\n`;
  }
}

export async function loadTsupConfig(
  cwd: string,
  configFile?: string,
): Promise<{ path?: string; data?: ReturnType<typeof defineConfig> }> {
  const configJoycon = new JoyCon()
  const configPath = await configJoycon.resolve({
    files: configFile
      ? [configFile]
      : [
          'tsup.config.ts',
          'tsup.config.cts',
          'tsup.config.mts',
          'tsup.config.js',
          'tsup.config.cjs',
          'tsup.config.mjs',
          'tsup.config.json',
          'package.json',
        ],
    cwd,
    stopDir: path.parse(cwd).root,
    packageKey: 'tsup',
  })

  if (configPath) {
    if (configPath.endsWith('.json')) {
      let data = await loadJson(configPath)
      if (configPath.endsWith('package.json')) {
        data = data.tsup
      }
      if (data) {
        return { path: configPath, data }
      }
      return {}
    }

    const config = await bundleRequire({
      filepath: configPath,
    })
    return {
      path: configPath,
      data: config.mod.tsup || config.mod.default || config.mod,
    }
  }

  return {}
}

setCredentialsByURI(uri: any, c: any) {
  assert(uri && typeof uri === "string", "registry URL is required");
  assert(c && typeof c === "object", "credentials are required");

  const nerfed = toNerfDart(uri);

  if (c.token) {
    this["set"](`${nerfed}:_authToken`, c.token, "user");
    this["del"](`${nerfed}:_password`, "user");
    this["del"](`${nerfed}:username`, "user");
    this["del"](`${nerfed}:email`, "user");
    this["del"](`${nerfed}:always-auth`, "user");
  } else if (c.username || c.password || c.email) {
    assert(c.username, "must include username");
    assert(c.password, "must include password");
    assert(c.email, "must include email address");

    this["del"](`${nerfed}:_authToken`, "user");

    const encoded = Buffer.from(c.password, "utf8").toString("base64");

    this["set"](`${nerfed}:_password`, encoded, "user");
    this["set"](`${nerfed}:username`, c.username, "user");
    this["set"](`${nerfed}:email`, c.email, "user");

    if (c.alwaysAuth !== undefined) {
      this["set"](`${nerfed}:always-auth`, c.alwaysAuth, "user");
    } else {
      this["del"](`${nerfed}:always-auth`, "user");
    }
  } else {
    throw new Error("No credentials to set.");
  }
}

export function useModalsStack<const T extends string>(modals: T[]): ModalStackReturnType<T> {
  const initialState = modals.reduce(
    (acc, modal) => ({ ...acc, [modal]: false }),
    {} as Record<T, boolean>
  );

  const [state, setState] = useState(initialState);

  const open = useCallback((modal: T) => {
    setState((current) => ({ ...current, [modal]: true }));
  }, []);

  const close = useCallback(
    (modal: T) => setState((current) => ({ ...current, [modal]: false })),
    []
  );

  const toggle = useCallback(
    (modal: T) => setState((current) => ({ ...current, [modal]: !current[modal] })),
    []
  );

  const closeAll = useCallback(() => setState(initialState), []);

  const register = useCallback(
    (modal: T) => ({
      opened: state[modal],
      onClose: () => close(modal),
      stackId: modal,
    }),
    [state]
  );

  return { state, open, close, closeAll, toggle, register };
}

export const wrapText = (text: SVGTextElement, width: number) => {
  if (!text.textContent) {
    return;
  }

  const words = text.textContent.split(/\s+/).reverse();
  let word: string | undefined;
  let line: string[] = [];
  let lineNumber = 0;
  const lineHeight = text.getBoundingClientRect().height;
  const y = text.getAttribute('y') || '0';

  text.textContent = null;

  let tspan = document.createElementNS(SVG_NAMESPACE_URI, 'tspan');
  text.appendChild(tspan);
  tspan.setAttribute('x', '0');
  tspan.setAttribute('y', y);
  tspan.setAttribute('dy', `${lineNumber++ * lineHeight}`);

  while ((word = words.pop())) {
    line.push(word);
    tspan.textContent = line.join(' ') + ' ';
    if (tspan.getComputedTextLength() > width && line.length > 1) {
      line.pop();
      tspan.textContent = line.join(' ') + ' ';
      line = [word];
      tspan = document.createElementNS(SVG_NAMESPACE_URI, 'tspan');
      text.appendChild(tspan);
      tspan.setAttribute('x', '0');
      tspan.setAttribute('y', y);
      tspan.setAttribute('dy', `${lineNumber++ * lineHeight}`);
      tspan.textContent = word;
    }
  }
};

override async doUpdateDefaultViewport() {
  if (!this._options.viewport && !this._options.screen)
    return;

  const screenSize = (this._options.screen || this._options.viewport)!;
  const viewportSize = (this._options.viewport || this._options.screen)!;
  await Promise.all([
    this._browser._browserSession.send('browsingContext.setViewport', {
      viewport: {
        width: viewportSize.width,
        height: viewportSize.height
      },
      devicePixelRatio: this._options.deviceScaleFactor || 1,
      userContexts: [this._userContextId()],
    }),
    this._browser._browserSession.send('emulation.setScreenOrientationOverride', {
      screenOrientation: getScreenOrientation(!!this._options.isMobile, screenSize),
      userContexts: [this._userContextId()],
    }),
    this._browser._browserSession.send('emulation.setScreenSettingsOverride', {
      screenArea: {
        width: screenSize.width,
        height: screenSize.height,
      },
      userContexts: [this._userContextId()],
    })
  ]);
}

private _formatPlainTextIndent(line: string) {
    const prev = this._lineAt(this._lineNum - 1);
    const prevIndent = this._prevIndent();
    const currIndent = this._currentIndent();

    if (
        currIndent > prevIndent &&
        !_isUndefinedOrWhitespace(prev) &&
        !this._builder.endsWith(MarkdownLineBreak) &&
        !this._builder.endsWith('\n\n') &&
        !_isHeader(prev)
    ) {
        this._builder = this._builder.slice(0, -1) + MarkdownLineBreak;
    }

    if (
        prevIndent > currIndent &&
        !_isUndefinedOrWhitespace(prev) &&
        !this._builder.endsWith(MarkdownLineBreak) &&
        !this._builder.endsWith('\n\n')
    ) {
        this._builder = this._builder.slice(0, -1) + MarkdownLineBreak;
    }

    if (prevIndent === 0 || this._builder.endsWith(MarkdownLineBreak) || this._builder.endsWith('\n\n')) {
        line = this._convertIndent(line);
    } else {
        line = line.trimStart();
    }
    return line;
}

private _getFilenameForApiItem(apiItem: ApiItem): string {
  if (apiItem.kind === ApiItemKind.Model) {
    return 'index.md';
  }

  let baseName: string = '';
  for (const hierarchyItem of apiItem.getHierarchy()) {
    // For overloaded methods, add a suffix such as "MyClass.myMethod_2".
    let qualifiedName: string = Utilities.getSafeFilenameForName(hierarchyItem.displayName);
    if (ApiParameterListMixin.isBaseClassOf(hierarchyItem)) {
      if (hierarchyItem.overloadIndex > 1) {
        // Subtract one for compatibility with earlier releases of API Documenter.
        // (This will get revamped when we fix GitHub issue #1308)
        qualifiedName += `_${hierarchyItem.overloadIndex - 1}`;
      }
    }

    switch (hierarchyItem.kind) {
      case ApiItemKind.Model:
      case ApiItemKind.EntryPoint:
      case ApiItemKind.EnumMember:
        break;
      case ApiItemKind.Package:
        baseName = Utilities.getSafeFilenameForName(PackageName.getUnscopedName(hierarchyItem.displayName));
        break;
      default:
        baseName += '.' + qualifiedName;
    }
  }
  return baseName + '.md';
}

export function formatEnum(value = 0, enumObject: any, isFlags?: boolean): string {
    const members = getEnumMembers(enumObject);
    if (value === 0) {
        return members.length > 0 && members[0][0] === 0 ? members[0][1] : "0";
    }
    if (isFlags) {
        const result: string[] = [];
        let remainingFlags = value;
        for (const [enumValue, enumName] of members) {
            if (enumValue > value) {
                break;
            }
            if (enumValue !== 0 && enumValue & value) {
                result.push(enumName);
                remainingFlags &= ~enumValue;
            }
        }
        if (remainingFlags === 0) {
            return result.join("|");
        }
    }
    else {
        for (const [enumValue, enumName] of members) {
            if (enumValue === value) {
                return enumName;
            }
        }
    }
    return value.toString();
}

function getAngle(node: nodes.Node): number {
	const textValue = node.getText();

	// Hue angle keyword `none` is the equivilient of `0deg`
	if (textValue === 'none') {
		return 0;
	}

	const m = /^(?<numberString>[-+]?[0-9]*\.?[0-9]+)(?<unit>deg|rad|grad|turn)?$/iu.exec(textValue);
	if (m?.groups?.['numberString']) {
		const value = Number.parseFloat(m.groups['numberString']);
		if (!Number.isNaN(value)) {
			switch (m.groups['unit']) {
				case 'deg': {
					return value % DEGREES_PER_CIRCLE;
				}

				case 'grad': {
					return (value * GRAD_TO_DEGREE_FACTOR) % DEGREES_PER_CIRCLE;
				}

				case 'rad': {
					return (value * RADIANS_TO_DEGREES_FACTOR) % DEGREES_PER_CIRCLE;
				}

				case 'turn': {
					return (value * DEGREES_PER_CIRCLE) % DEGREES_PER_CIRCLE;
				}

				default: {
					// Unitless angles are treated as degrees
					return value % DEGREES_PER_CIRCLE;
				}
			}
		}
	}

	throw new Error(`Failed to parse '${textValue}' as angle`);
}

export function convert2RegExp(pattern: string): RegExp | undefined {
	const separator = process.platform === 'win32' ? '\\\\' : '\\/';
	const fileChar = `[^${separator}]`;
	function convertNode(node: Node): string {
		switch (node.type) {
			case NodeType.separator:
				return separator;
				break;
			case NodeType.text:
				return node.value;
				break;
			case NodeType.questionMark:
				return fileChar;
				break;
			case NodeType.star:
				return `${fileChar}*?`;
				break;
			case NodeType.globStar:
				return `(?:${fileChar}|(?:(?:${fileChar}${separator})+${fileChar}))*?`;
			case NodeType.bracket:
				return `[${node.value}]`;
			case NodeType.brace: {
				const buffer: string[] = [];
				for (const child of node.alternatives) {
					buffer.push(convertNode(child));
				}
				return `(?:${buffer.join('|')})`;
			}
		}
	}

	try {
		const buffer: string[] = ['^'];

		const parser = new PatternParser(pattern);
		let node: Node | undefined;
		while ((node = parser.next()) !== undefined) {
			buffer.push(convertNode(node));
		}
		return buffer.length > 0 ? new RegExp(buffer.join('')) : undefined;
	} catch (err) {
		console.error(err);
		return undefined;
	}
}

export function doRename(
  document: TextDocument,
  position: Position,
  newName: string,
  htmlDocument: HTMLDocument
): WorkspaceEdit | null {
  const offset = document.offsetAt(position);
  const node = htmlDocument.findNodeAt(offset);

  if (!node.tag) {
    return null;
  }

  if (!isWithinTagRange(node, offset, node.tag)) {
    return null;
  }

  const edits: TextEdit[] = [];

  const startTagRange: Range = {
    start: document.positionAt(node.start + '<'.length),
    end: document.positionAt(node.start + '<'.length + node.tag.length)
  };
  edits.push({
    range: startTagRange,
    newText: newName
  });

  if (node.endTagStart) {
    const endTagRange: Range = {
      start: document.positionAt(node.endTagStart + '</'.length),
      end: document.positionAt(node.endTagStart + '</'.length + node.tag.length)
    };
    edits.push({
      range: endTagRange,
      newText: newName
    });
  }

  const changes = {
    [document.uri.toString()]: edits
  };

  return {
    changes
  };
}

export function stringifyObject(obj: any, indent: string, stringifyLiteral: (val: any) => string): string {
	if (obj !== null && typeof obj === 'object') {
		const newIndent = indent + '\t';
		if (Array.isArray(obj)) {
			if (obj.length === 0) {
				return '[]';
			}
			let result = '[\n';
			for (let i = 0; i < obj.length; i++) {
				result += newIndent + stringifyObject(obj[i], newIndent, stringifyLiteral);
				if (i < obj.length - 1) {
					result += ',';
				}
				result += '\n';
			}
			result += indent + ']';
			return result;
		} else {
			const keys = Object.keys(obj);
			if (keys.length === 0) {
				return '{}';
			}
			let result = '{\n';
			for (let i = 0; i < keys.length; i++) {
				const key = keys[i];

				result += newIndent + JSON.stringify(key) + ': ' + stringifyObject(obj[key], newIndent, stringifyLiteral);
				if (i < keys.length - 1) {
					result += ',';
				}
				result += '\n';
			}
			result += indent + '}';
			return result;
		}
	}
	return stringifyLiteral(obj);
}

export const NotebookSyncFeature: Feature<_Notebooks, NotebookSyncFeatureShape> = (Base) => {
	return class extends Base {
		public get synchronization() {
			return {
				onDidOpenNotebookDocument: (handler: NotificationHandler1<DidOpenNotebookDocumentParams>): Disposable => {
					return this.connection.onNotification(DidOpenNotebookDocumentNotification.type, (params) => {
						return handler(params);
					});
				},
				onDidChangeNotebookDocument: (handler: NotificationHandler1<DidChangeNotebookDocumentParams>): Disposable => {
					return this.connection.onNotification(DidChangeNotebookDocumentNotification.type, (params) => {
						return handler(params);
					});
				},
				onDidSaveNotebookDocument: (handler: NotificationHandler1<DidSaveNotebookDocumentParams>): Disposable => {
					return this.connection.onNotification(DidSaveNotebookDocumentNotification.type, (params) => {
						return handler(params);
					});
				},
				onDidCloseNotebookDocument: (handler: NotificationHandler1<DidCloseNotebookDocumentParams>): Disposable => {
					return this.connection.onNotification(DidCloseNotebookDocumentNotification.type, (params) => {
						return handler(params);
					});
				}
			};
		}
	};
};

export function getDocumentContext(documentUri: string, workspaceFolders: WorkspaceFolder[]): DocumentContext {
	function getRootFolder(): string | undefined {
		for (const folder of workspaceFolders) {
			let folderURI = folder.uri;
			if (!endsWith(folderURI, '/')) {
				folderURI = folderURI + '/';
			}
			if (startsWith(documentUri, folderURI)) {
				return folderURI;
			}
		}
		return undefined;
	}

	return {
		resolveReference: (ref: string, base = documentUri) => {
			if (ref.match(/^\w[\w\d+.-]*:/)) {
				// starts with a schema
				return ref;
			}
			if (ref[0] === '/') { // resolve absolute path against the current workspace folder
				const folderUri = getRootFolder();
				if (folderUri) {
					return folderUri + ref.substr(1);
				}
			}
			const baseUri = URI.parse(base);
			const baseUriDir = baseUri.path.endsWith('/') ? baseUri : Utils.dirname(baseUri);
			return Utils.resolvePath(baseUriDir, ref).toString(true);
		},
	};
}

function getActionLabel(node: ActionNode) {
	switch (node.action) {
		case 'sync-workspace':
			return 'SyncWorkspace';

		case 'sync-project':
			return `SyncProject(${node.params.projectId})`;

		case 'setup-proto':
			return `SetupProto(${node.params.version})`;

		case 'setup-environment':
			return `SetupEnvironment(${node.params.toolchainId}${node.params.root ? `, ${node.params.root}` : ''})`;

		case 'setup-toolchain':
			return `SetupToolchain(${node.params.toolchain.id}${node.params.toolchain.req ? `:${node.params.toolchain.req}` : ''})`;

		case 'install-dependencies':
			return `InstallDependencies(${node.params.toolchainId}${node.params.root ? `, ${node.params.root}` : ''})`;

		case 'run-task':
			if (node.params.persistent) {
				return `RunPersistentTask(${node.params.target})`;
			} else if (node.params.interactive) {
				return `RunInteractiveTask(${node.params.target})`;
			} else {
				return `RunTask(${node.params.target})`;
			}
	}
}

async function getRemixE2EWebServerInfo(
  tree: Tree,
  projectName: string,
  configFilePath: string,
  isPluginBeingAdded: boolean
) {
  const nxJson = readNxJson(tree);
  let e2ePort = isPluginBeingAdded ? 3000 : 4200;

  const defaultServeTarget = isPluginBeingAdded ? 'dev' : 'serve';
  const serveTargetOptions = readTargetDefaultsForTarget(
    defaultServeTarget,
    nxJson.targetDefaults
  )?.options;

  if (serveTargetOptions?.port) {
    e2ePort = serveTargetOptions.port;
  }

  return getE2EWebServerInfo(
    tree,
    projectName,
    {
      plugin: '@nx/remix/plugin',
      serveTargetName: 'serveTargetName',
      serveStaticTargetName: 'serveStaticTargetName',
      configFilePath,
    },
    {
      defaultServeTargetName: defaultServeTarget,
      defaultServeStaticTargetName: 'serve-static',
      defaultE2EWebServerAddress: `http://localhost:${e2ePort}`,
      defaultE2ECiBaseUrl: 'http://localhost:3000',
      defaultE2EPort: e2ePort,
    },
    isPluginBeingAdded
  );
}

generate(): string {
  const cmd = this.command
  const unsortedFlags = Object.entries(cmd.flags || {})
    .filter(([, v]) => !v.hidden)
    .map(([k, v]) => {
      v.name = k
      return v
    })

  const flags =
    determineSortOrder(this.opts.flagSortOrder) === 'alphabetical'
      ? sortBy(unsortedFlags, (f) => [!f.char, f.char, f.name])
      : unsortedFlags

  const args = Object.values(ensureArgObject(cmd.args)).filter((a) => !a.hidden)
  const output = compact(
    this.sections().map(({generate, header}) => {
      const body = generate({args, cmd, flags}, header)
      // Generate can return a list of sections
      if (Array.isArray(body)) {
        return body
          .map((helpSection) => helpSection && helpSection.body && this.section(helpSection.header, helpSection.body))
          .join('\n\n')
      }

      return body && this.section(header, body)
    }),
  ).join('\n\n')
  return output
}

function reportAuthError (
  err: Error,
  msg: { hint?: string },
  config?: Config
): ErrorInfo {
  const foundSettings = [] as string[]
  for (const [key, value] of Object.entries(config?.authConfig ?? {})) {
    if (key[0] === '@') {
      foundSettings.push(`${key}=${String(value)}`)
      continue
    }
    if (
      key.endsWith('_auth') ||
      key.endsWith('_authToken') ||
      key.endsWith('username') ||
      key.endsWith('_password')
    ) {
      foundSettings.push(`${key}=${hideSecureInfo(key, value)}`)
    }
  }
  let output = msg.hint ? `${msg.hint}${EOL}${EOL}` : ''

  if (foundSettings.length === 0) {
    output += `No authorization settings were found in the configs.
Try to log in to the registry by running "pnpm login"
or add the auth tokens manually to the ~/.npmrc file.`
  } else {
    output += `These authorization settings were found:
${foundSettings.join('\n')}`
  }
  return {
    title: err.message,
    body: output,
  }
}

export const mapTsExtensions = (
	filePath: string,
) => {
	const splitPath = filePath.split('?');
	const pathQuery = splitPath[1] ? `?${splitPath[1]}` : '';
	const [pathname] = splitPath;
	const extension = path.extname(pathname);

	const tryPaths: string[] = [];

	const tryExtensions = tsExtensions[extension];
	if (tryExtensions) {
		const extensionlessPath = pathname.slice(0, -extension.length);

		tryPaths.push(
			...tryExtensions.map(
				extension_ => (
					extensionlessPath
					+ extension_
					+ pathQuery
				),
			),
		);
	}

	const guessExtensions = (
		(
			!(filePath.startsWith(fileUrlPrefix) || isFilePath(pathname))
			|| pathname.includes(nodeModulesPath)
			|| pathname.includes('/node_modules/') // For file:// URLs on Windows
		)
			? dependencyExtensions
			: localExtensions
	);
	tryPaths.push(
		...guessExtensions.map(
			extension_ => (
				pathname
				+ extension_
				+ pathQuery
			),
		),
	);

	return tryPaths;
};

private getPropertyNamesCandidates(schema: JSONSchemaRef): { candidates: string[]; impossible: boolean } {
  let impossible = false;

  const collect = (node: JSONSchemaRef): Set<string> | null => {
    if (!node || typeof node !== 'object') return null;

    if (Array.isArray(node.allOf) && node.allOf.length) {
      let intersection = null;
      for (const part of node.allOf) {
        const partSet = collect(part);
        if (!partSet) continue;
        intersection = intersection ? new Set([...intersection].filter((v) => partSet.has(v))) : new Set(partSet);
        if (intersection.size === 0) {
          impossible = true;
          return new Set();
        }
      }
      if (intersection) return intersection;
    }

    const result = new Set<string>();
    if (typeof node.const === 'string') result.add(node.const);
    node.enum?.forEach((val) => typeof val === 'string' && result.add(val));
    node.anyOf?.forEach((branch) => collect(branch)?.forEach((val) => result.add(val)));
    node.oneOf?.forEach((branch) => collect(branch)?.forEach((val) => result.add(val)));

    return result.size ? result : null;
  };

  const set = collect(schema);
  return { candidates: set ? [...set] : [], impossible };
}

export function generateTopBugsSection(
  issues: CategorizedIssue[],
  maxItems: number = 20,
): string {
  const bugs = issues.filter(
    (issue) =>
      issue.type === 'issue' &&
      (issue.labels.some((l) => l.toLowerCase().includes('bug')) ||
        issue.title.toLowerCase().includes('bug') ||
        issue.flags.isUrgent),
  )

  if (bugs.length === 0) {
    return '## 🐛 Top Bugs\n\nNo bugs found.\n\n'
  }

  const sections: string[] = []

  sections.push('## 🐛 Top Bugs')
  sections.push('')
  sections.push(
    `Showing top ${Math.min(maxItems, bugs.length)} bugs by priority.`,
  )
  sections.push('')

  const topBugs = sortByPriority(bugs).slice(0, maxItems)

  for (const bug of topBugs) {
    const priority = calculatePriority(bug)
    const flags = formatFlags(bug)

    sections.push(
      `- ${formatIssueLink(bug)} (Priority: ${priority.toFixed(1)})`,
    )
    sections.push(
      `  - **Category**: ${bug.categorization.primary}${bug.categorization.secondary ? ` / ${bug.categorization.secondary}` : ''}`,
    )
    sections.push(`  - **Created**: ${formatRelativeDate(bug.created_at)}`)
    if (flags) sections.push(`  - **Flags**: ${flags}`)
  }

  sections.push('')

  return sections.join('\n')
}
